/*
 * Line Follower Robot
 * Hardware: Arduino Uno, 2 DC Motors, 2 IR Sensors
 * 
 * This code implements a basic line following algorithm
 * using two IR sensors and differential drive control.
 */

// Motor pins
const int MOTOR_LEFT_PWM = 5;
const int MOTOR_LEFT_DIR1 = 6;
const int MOTOR_LEFT_DIR2 = 7;

const int MOTOR_RIGHT_PWM = 9;
const int MOTOR_RIGHT_DIR1 = 10;
const int MOTOR_RIGHT_DIR2 = 11;

// IR sensor pins
const int IR_LEFT = A0;
const int IR_RIGHT = A1;

// Speed settings
const int BASE_SPEED = 150;  // 0-255
const int TURN_SPEED = 100;

// Sensor threshold (calibrate based on your surface)
const int THRESHOLD = 500;

void setup() {
  // Initialize serial for debugging
  Serial.begin(9600);

  // Configure motor pins as outputs
  pinMode(MOTOR_LEFT_PWM, OUTPUT);
  pinMode(MOTOR_LEFT_DIR1, OUTPUT);
  pinMode(MOTOR_LEFT_DIR2, OUTPUT);

  pinMode(MOTOR_RIGHT_PWM, OUTPUT);
  pinMode(MOTOR_RIGHT_DIR1, OUTPUT);
  pinMode(MOTOR_RIGHT_DIR2, OUTPUT);

  // Configure IR sensor pins as inputs
  pinMode(IR_LEFT, INPUT);
  pinMode(IR_RIGHT, INPUT);

  Serial.println("Line Follower Robot Initialized");
  delay(2000);  // Wait 2 seconds before starting
}

void loop() {
  // Read IR sensors
  int leftSensor = analogRead(IR_LEFT);
  int rightSensor = analogRead(IR_RIGHT);

  // Debug output
  Serial.print("Left: ");
  Serial.print(leftSensor);
  Serial.print(" Right: ");
  Serial.println(rightSensor);

  // Determine line position
  bool leftOnLine = (leftSensor > THRESHOLD);
  bool rightOnLine = (rightSensor > THRESHOLD);

  // Line following logic
  if (leftOnLine && rightOnLine) {
    // Both sensors on line - move forward
    moveForward(BASE_SPEED);
  }
  else if (leftOnLine && !rightOnLine) {
    // Left sensor on line - turn left
    turnLeft(TURN_SPEED);
  }
  else if (!leftOnLine && rightOnLine) {
    // Right sensor on line - turn right
    turnRight(TURN_SPEED);
  }
  else {
    // Both sensors off line - stop
    stopMotors();
  }

  delay(10);  // Small delay for stability
}

void moveForward(int speed) {
  // Left motor forward
  digitalWrite(MOTOR_LEFT_DIR1, HIGH);
  digitalWrite(MOTOR_LEFT_DIR2, LOW);
  analogWrite(MOTOR_LEFT_PWM, speed);

  // Right motor forward
  digitalWrite(MOTOR_RIGHT_DIR1, HIGH);
  digitalWrite(MOTOR_RIGHT_DIR2, LOW);
  analogWrite(MOTOR_RIGHT_PWM, speed);
}

void turnLeft(int speed) {
  // Left motor slow/stop
  digitalWrite(MOTOR_LEFT_DIR1, LOW);
  digitalWrite(MOTOR_LEFT_DIR2, LOW);
  analogWrite(MOTOR_LEFT_PWM, 0);

  // Right motor forward
  digitalWrite(MOTOR_RIGHT_DIR1, HIGH);
  digitalWrite(MOTOR_RIGHT_DIR2, LOW);
  analogWrite(MOTOR_RIGHT_PWM, speed);
}

void turnRight(int speed) {
  // Left motor forward
  digitalWrite(MOTOR_LEFT_DIR1, HIGH);
  digitalWrite(MOTOR_LEFT_DIR2, LOW);
  analogWrite(MOTOR_LEFT_PWM, speed);

  // Right motor slow/stop
  digitalWrite(MOTOR_RIGHT_DIR1, LOW);
  digitalWrite(MOTOR_RIGHT_DIR2, LOW);
  analogWrite(MOTOR_RIGHT_PWM, 0);
}

void stopMotors() {
  // Stop both motors
  digitalWrite(MOTOR_LEFT_DIR1, LOW);
  digitalWrite(MOTOR_LEFT_DIR2, LOW);
  analogWrite(MOTOR_LEFT_PWM, 0);

  digitalWrite(MOTOR_RIGHT_DIR1, LOW);
  digitalWrite(MOTOR_RIGHT_DIR2, LOW);
  analogWrite(MOTOR_RIGHT_PWM, 0);
}
